#include<bits/stdc++.h>
using namespace std;
int a=0;
string s;
int main()
{
	cin>>s;
	for(int i=0;i<s.size();i++)
	{
		if(s[0]==')')
		{
			cout<<"NO";
			return 0;
		}
		if(a<0)
		{
			cout<<"NO";
			return 0;
		}
		if(s[i]=='(')
			a+=1;
		if(s[i]==')')
			a-=1;
	}
	if(a==0)
		cout<<"YES";
	else
		cout<<"NO";
	return 0;
}
